import React from 'react';

interface JobInfoSectionProps {
    data: any;
    showReRegister?: boolean;
    onReRegister?: () => void;
}

const getStatusLabel = (status: string): string => {
    switch (status) {
        case 'RECRUITING': return '매칭대기';
        case 'MATCHED': return '예약완료';
        case 'ONGOING': return '진행중';
        case 'COMPLETED': return '완료';
        case 'CANCELLED': return '취소';
        default: return status || '';
    }
};

const getStatusClass = (status: string): string => {
    switch (status) {
        case 'RECRUITING': return 'status';         // 초록 (기본)
        case 'MATCHED': return 'status ing';         // 파랑
        case 'ONGOING': return 'status ing';         // 파랑
        case 'COMPLETED': return 'status finish';    // 회색
        case 'CANCELLED': return 'status cancel';    // 빨강
        default: return 'status';
    }
};

export const JobInfoSection: React.FC<JobInfoSectionProps> = ({ data, showReRegister, onReRegister }) => (
    <section className="bg-gray">
        <div className="inner-box">
            <div className="col-info">
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <p className="number">
                        공고번호 : {data.jobPostingCode}
                        <span className={getStatusClass(data.status)} style={{ marginLeft: '8px' }}>{getStatusLabel(data.status)}</span>
                    </p>
                    {showReRegister && (
                        <button
                            type="button"
                            className="edit-btn"
                            onClick={onReRegister}
                        >
                            공고 재등록
                        </button>
                    )}
                </div>
                <p className="location">{data.address}</p>
                <p className="address">{data.addressDetail}</p>
                <div className="tag-list">
                    <span className="tag color">{data.categoryName}</span>
                    <span className="tag">{data.workTypeName}</span>
                </div>
                <div className="round-box mt10">
                    <div className="round-body">
                        <div className="info-row">
                            <span className="label">급여</span>
                            <span className="cont">
                {data.workTypeName === '시간제' ? '시급' : '일급'} {data.dailyPay?.toLocaleString()}원
                                {data.negotiable && <span></span>}
              </span>
                        </div>
                        <div className="info-row">
                            <span className="label">간병일자</span>
                            <span className="cont">
                {data.careStartDate} ~ {data.careEndDate} ({data.totalDays}일)
              </span>
                        </div>
                        {data.workTypeName === '시간제' && (
                            <div className="info-row">
                                <span className="label">돌봄시간</span>
                                <span className="cont">{data.workStartTime} ~ {data.workEndTime}</span>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    </section>
);
